-- 0037_promote_gn_sources_full.sql
-- APPLIED-STATE NOTE (2026-07-12): prod already has 150 gn_census feeds live
--   (0036 batch = 54  +  a hand-curated ~96 high-confidence subset of the set below).
-- This file is the FULL 226-feed quality set. It is idempotent (ON CONFLICT DO NOTHING):
-- applying it simply ADDS the long-tail feeds (hyper-local + non-Latin-named outlets) that
-- were intentionally held back. Apply only if you want the full long tail.
--
-- Promotes QUALITY publishers discovered via the Google News census (Tom News, 2026-07-12)
-- to first-class RSS feeds so the Google-News hybrid fill can retire. Quality-filtered:
-- image-carrying + active, or authoritative. Every feed verified to parse. feed_url UNIQUE
-- + ON CONFLICT DO NOTHING → idempotent and safe to re-apply over the earlier 0036 batch.
-- 226 feeds (212 carry images natively → NewsFirst gets photos without decoding).
on conflict (feed_url) do nothing;
update public.sources set poll_interval_s = 1200 where meta->>'origin' = 'gn_census';
